using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // ---------------------------------------------------------------
    // AddItem
    // ---------------------------------------------------------------

    [TestMethod]
    public void AddItem_SingleItem_AppearsInCart()
    {
        _cart.AddItem("SKU-001", 2, 9.99m);

        Assert.AreEqual(1, _cart.Items.Count);
        Assert.AreEqual(2, _cart.Items["SKU-001"].Quantity);
        Assert.AreEqual(9.99m, _cart.Items["SKU-001"].Price);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantityAndUsesLatestPrice()
    {
        _cart.AddItem("SKU-001", 1, 5.00m);
        _cart.AddItem("SKU-001", 3, 6.00m);

        Assert.AreEqual(1, _cart.Items.Count);
        Assert.AreEqual(4, _cart.Items["SKU-001"].Quantity);
        Assert.AreEqual(6.00m, _cart.Items["SKU-001"].Price);
    }

    [TestMethod]
    public void AddItem_MultipleDistinctSkus_AllAppear()
    {
        _cart.AddItem("A", 1, 1.00m);
        _cart.AddItem("B", 2, 2.00m);
        _cart.AddItem("C", 3, 3.00m);

        Assert.AreEqual(3, _cart.Items.Count);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem(sku!, 1, 10m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_Throws(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU-001", quantity, 10m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU-001", 1, -1m));
    }

    [TestMethod]
    public void AddItem_ZeroPrice_Succeeds()
    {
        _cart.AddItem("FREE", 1, 0m);

        Assert.AreEqual(0m, _cart.Items["FREE"].Price);
    }

    // ---------------------------------------------------------------
    // RemoveItem
    // ---------------------------------------------------------------

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _cart.AddItem("SKU-001", 1, 10m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0, _cart.Items.Count);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFoundException()
    {
        Assert.ThrowsException<KeyNotFoundException>(
            () => _cart.RemoveItem("MISSING"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void RemoveItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.RemoveItem(sku!));
    }

    [TestMethod]
    public void RemoveItem_OnlyRemovesTargetItem()
    {
        _cart.AddItem("A", 1, 1m);
        _cart.AddItem("B", 1, 2m);

        _cart.RemoveItem("A");

        Assert.AreEqual(1, _cart.Items.Count);
        Assert.IsTrue(_cart.Items.ContainsKey("B"));
    }

    // ---------------------------------------------------------------
    // CalculateTotal
    // ---------------------------------------------------------------

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-001", 3, 4.50m);

        Assert.AreEqual(13.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_SumsCorrectly()
    {
        _cart.AddItem("A", 2, 10.00m); // 20.00
        _cart.AddItem("B", 1, 5.50m);  //  5.50

        Assert.AreEqual(25.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemoval_ExcludesRemovedItem()
    {
        _cart.AddItem("A", 1, 10.00m);
        _cart.AddItem("B", 1, 20.00m);
        _cart.RemoveItem("A");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    // ---------------------------------------------------------------
    // ApplyCoupon
    // ---------------------------------------------------------------

    [TestMethod]
    [DataRow("SAVE10", 10)]
    [DataRow("save10", 10)]
    [DataRow("SAVE20", 20)]
    [DataRow("HALF", 50)]
    public void ApplyCoupon_ValidCode_AppliesExpectedDiscount(string code, int discountPct)
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon(code);

        var expected = 100.00m * (1 - discountPct / 100m);
        Assert.AreEqual(expected, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_UnknownCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void ApplyCoupon_InvalidCode_Throws(string? code)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_AppliedTwice_UsesLatestCoupon()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10"); // 10 %
        _cart.ApplyCoupon("SAVE20"); // 20 %

        Assert.AreEqual(80.00m, _cart.CalculateTotal());
    }

    // ---------------------------------------------------------------
    // Combined / integration-style scenarios
    // ---------------------------------------------------------------

    [TestMethod]
    public void FullWorkflow_AddRemoveCouponTotal()
    {
        _cart.AddItem("A", 2, 15.00m); // 30
        _cart.AddItem("B", 1, 20.00m); // 20
        _cart.RemoveItem("B");          // -20
        _cart.ApplyCoupon("SAVE10");    // 10% off 30 => 27

        Assert.AreEqual(27.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_CouponOnMultipleItems_RoundsCorrectly()
    {
        _cart.AddItem("A", 3, 3.33m); // subtotal = 9.99
        _cart.ApplyCoupon("SAVE10");   // 10% off => 8.991 → rounds to 8.99

        Assert.AreEqual(8.99m, _cart.CalculateTotal());
    }
}

